#include <stdio.h>
#include <stdbool.h>

#define MEMORY_SIZE 1000

typedef struct {
    int start;
    int size;
    int process_id;  // -1 if free
} MemoryBlock;

MemoryBlock memory[10];
int num_blocks = 1;

void initialize_memory() {
    memory[0].start = 0;
    memory[0].size = MEMORY_SIZE;
    memory[0].process_id = -1;  // Free
}

int allocate_first_fit(int process_id, int size) {
    for (int i = 0; i < num_blocks; i++) {
        if (memory[i].process_id == -1 && memory[i].size >= size) {
            // Found free block
            if (memory[i].size > size) {
                // Split block
                memory[num_blocks].start = memory[i].start + size;
                memory[num_blocks].size = memory[i].size - size;
                memory[num_blocks].process_id = -1;
                num_blocks++;
            }
            memory[i].process_id = process_id;
            memory[i].size = size;
            return memory[i].start;
        }
    }
    return -1;  // No suitable block found
}

bool deallocate(int process_id) {
    for (int i = 0; i < num_blocks; i++) {
        if (memory[i].process_id == process_id) {
            memory[i].process_id = -1;  // Mark as free
            // Merge with adjacent free blocks (compaction simplified)
            return true;
        }
    }
    return false;
}

int main() {
    initialize_memory();

    int addr1 = allocate_first_fit(1, 200);  // Allocate 200 bytes
    int addr2 = allocate_first_fit(2, 300);  // Allocate 300 bytes
    int addr3 = allocate_first_fit(3, 150);  // Allocate 150 bytes

    printf("Process 1 at address %d\n", addr1);
    printf("Process 2 at address %d\n", addr2);
    printf("Process 3 at address %d\n", addr3);

    deallocate(2);  // Free process 2
    int addr4 = allocate_first_fit(4, 100);  // Allocate 100 bytes
    printf("Process 4 at address %d\n", addr4);

    return 0;
}
